-- Create "monitor_definitions" table
CREATE TABLE "monitor_definitions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "name" character varying NOT NULL,
  "enabled" boolean NOT NULL DEFAULT true,
  "scope" character varying NOT NULL DEFAULT 'account',
  "scope_ref" character varying NOT NULL DEFAULT '',
  "interval_seconds" bigint NOT NULL DEFAULT 300,
  "model" character varying NOT NULL DEFAULT '',
  "request_method" character varying NOT NULL DEFAULT '',
  "request_url" character varying NOT NULL DEFAULT '',
  "request_headers" jsonb NULL,
  "request_body" character varying NOT NULL DEFAULT '',
  "expected_status_codes" jsonb NULL,
  "response_json_path" character varying NOT NULL DEFAULT '',
  "response_contains" character varying NOT NULL DEFAULT '',
  PRIMARY KEY ("id")
);
-- Create index "monitordefinition_enabled" to table: "monitor_definitions"
CREATE INDEX "monitordefinition_enabled" ON "monitor_definitions" ("enabled");
-- Create index "monitordefinition_scope" to table: "monitor_definitions"
CREATE INDEX "monitordefinition_scope" ON "monitor_definitions" ("scope");
-- Create "monitor_request_templates" table
CREATE TABLE "monitor_request_templates" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "name" character varying NOT NULL,
  "description" character varying NOT NULL DEFAULT '',
  "request_method" character varying NOT NULL DEFAULT '',
  "request_url" character varying NOT NULL DEFAULT '',
  "request_headers" jsonb NULL,
  "request_body" character varying NOT NULL DEFAULT '',
  "expected_status_codes" jsonb NULL,
  "response_json_path" character varying NOT NULL DEFAULT '',
  "response_contains" character varying NOT NULL DEFAULT '',
  PRIMARY KEY ("id")
);
-- Create index "monitorrequesttemplate_name" to table: "monitor_request_templates"
CREATE INDEX "monitorrequesttemplate_name" ON "monitor_request_templates" ("name");
-- Create "monitor_run_results" table
CREATE TABLE "monitor_run_results" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "monitor_id" bigint NOT NULL,
  "run_id" character varying NOT NULL,
  "ok" boolean NOT NULL DEFAULT false,
  "checked_count" bigint NOT NULL DEFAULT 0,
  "ok_count" bigint NOT NULL DEFAULT 0,
  "latency_ms" bigint NOT NULL DEFAULT 0,
  "trigger" character varying NOT NULL DEFAULT 'manual',
  "results" jsonb NULL,
  PRIMARY KEY ("id")
);
-- Create index "monitorrunresult_monitor_id" to table: "monitor_run_results"
CREATE INDEX "monitorrunresult_monitor_id" ON "monitor_run_results" ("monitor_id");
-- Create index "monitorrunresult_run_id" to table: "monitor_run_results"
CREATE INDEX "monitorrunresult_run_id" ON "monitor_run_results" ("run_id");
